//! Video decode: ffmpeg subprocess -> RGB24 frame stream + presentation timestamps.
//!
//! ffmpeg does not emit per-frame PTS on a rawvideo pipe, so timestamps are reconstructed
//! from the *output* frame rate (the rate after any `-r` downsample), which is exact for
//! constant-rate sampling — the regime third-eye runs under. Frames are read one at a time
//! off the pipe, so memory stays O(one frame), not O(whole video).
//!
//! RGB24 packed (stride = width*3) is the buffer convention the gnosis vision crates expect
//! (`image::RgbImage` / raw `Vec<u8>`), so frames hand downstream without reformatting.

use std::io::{self, Read};
use std::process::{Child, ChildStdout, Command, Stdio};

/// Static facts about a video stream, from `ffprobe`.
#[derive(Debug, Clone)]
pub struct VideoInfo {
    pub width: u32,
    pub height: u32,
    /// Source frame rate as a rational (num/den), e.g. 30000/1001 for 29.97.
    pub fps_num: u32,
    pub fps_den: u32,
    /// Duration in seconds (0.0 if ffprobe could not determine it).
    pub duration_s: f64,
    /// Frame count if ffprobe reports it (often 0 for streamed/variable inputs).
    pub nb_frames: u64,
}

impl VideoInfo {
    /// Source frames per second as a float.
    pub fn fps(&self) -> f64 {
        if self.fps_den == 0 {
            0.0
        } else {
            self.fps_num as f64 / self.fps_den as f64
        }
    }
}

/// One decoded frame: packed RGB24, plus index and presentation time.
#[derive(Clone)]
pub struct Frame {
    /// 0-based index in the decoded (post-downsample) stream.
    pub index: u64,
    /// Presentation time in seconds, reconstructed from the output rate.
    pub pts_s: f64,
    pub width: u32,
    pub height: u32,
    /// Packed RGB24, len == width*height*3, stride == width*3.
    pub rgb: Vec<u8>,
}

impl std::fmt::Debug for Frame {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("Frame")
            .field("index", &self.index)
            .field("pts_s", &self.pts_s)
            .field("width", &self.width)
            .field("height", &self.height)
            .field("rgb_len", &self.rgb.len())
            .finish()
    }
}

/// Decode parameters. Defaults decode every frame at source resolution.
#[derive(Debug, Clone, Default)]
pub struct DecodeOptions {
    /// Resample to this output frame rate (frame stride). `None` = source rate.
    /// third-eye's cadence governor sets this to throttle "as fast as stable".
    pub fps: Option<f64>,
    /// Scale to (w, h). `None` = source resolution. Aspect is not auto-preserved;
    /// pass the dims you want.
    pub scale: Option<(u32, u32)>,
    /// Seek to this start time (seconds) before decoding.
    pub start_s: Option<f64>,
    /// Stop after this many output frames (`None` = until EOF).
    pub max_frames: Option<u64>,
}

/// Probe a video for its static info via `ffprobe`.
pub fn probe(path: &str) -> io::Result<VideoInfo> {
    // One key=value line per field; stable, easy to parse, locale-independent.
    let out = Command::new("ffprobe")
        .args([
            "-v",
            "error",
            "-select_streams",
            "v:0",
            "-show_entries",
            "stream=width,height,r_frame_rate,nb_frames,duration",
            "-of",
            "default=noprint_wrappers=1:nokey=0",
            path,
        ])
        .output()?;
    if !out.status.success() {
        return Err(io::Error::other(format!(
            "ffprobe failed ({}): {}",
            out.status,
            String::from_utf8_lossy(&out.stderr).trim()
        )));
    }
    let text = String::from_utf8_lossy(&out.stdout);
    let mut width = 0u32;
    let mut height = 0u32;
    let mut fps_num = 0u32;
    let mut fps_den = 1u32;
    let mut duration_s = 0.0f64;
    let mut nb_frames = 0u64;
    for line in text.lines() {
        let Some((k, v)) = line.split_once('=') else {
            continue;
        };
        let v = v.trim();
        match k.trim() {
            "width" => width = v.parse().unwrap_or(0),
            "height" => height = v.parse().unwrap_or(0),
            "r_frame_rate" => {
                if let Some((n, d)) = v.split_once('/') {
                    fps_num = n.parse().unwrap_or(0);
                    fps_den = d.parse().unwrap_or(1).max(1);
                }
            }
            "duration" => duration_s = v.parse().unwrap_or(0.0),
            "nb_frames" => nb_frames = v.parse().unwrap_or(0),
            _ => {}
        }
    }
    if width == 0 || height == 0 {
        return Err(io::Error::other(
            "ffprobe could not determine video dimensions",
        ));
    }
    Ok(VideoInfo {
        width,
        height,
        fps_num,
        fps_den,
        duration_s,
        nb_frames,
    })
}

/// A streaming RGB24 frame decoder backed by an ffmpeg subprocess.
///
/// Implements `Iterator<Item = io::Result<Frame>>`.
pub struct Decoder {
    child: Child,
    stdout: ChildStdout,
    out_w: u32,
    out_h: u32,
    frame_bytes: usize,
    out_fps: f64,
    index: u64,
    max_frames: Option<u64>,
    done: bool,
}

impl Decoder {
    /// Open `path` and start decoding under `opts`. Needs the source `info` (from [`probe`])
    /// to resolve output dimensions and the timestamp rate.
    pub fn open(path: &str, info: &VideoInfo, opts: &DecodeOptions) -> io::Result<Self> {
        let (out_w, out_h) = opts.scale.unwrap_or((info.width, info.height));
        let out_fps = opts.fps.unwrap_or_else(|| info.fps());
        let frame_bytes = (out_w as usize) * (out_h as usize) * 3;

        let mut args: Vec<String> = Vec::new();
        args.push("-v".into());
        args.push("error".into());
        // -ss before -i = fast keyframe seek.
        if let Some(s) = opts.start_s {
            args.push("-ss".into());
            args.push(format!("{s}"));
        }
        args.push("-i".into());
        args.push(path.into());
        if let Some(f) = opts.fps {
            args.push("-r".into());
            args.push(format!("{f}"));
        }
        if let Some((w, h)) = opts.scale {
            args.push("-vf".into());
            args.push(format!("scale={w}:{h}"));
        }
        // Cap inside ffmpeg too, so it stops producing once we have enough.
        if let Some(n) = opts.max_frames {
            args.push("-frames:v".into());
            args.push(format!("{n}"));
        }
        args.push("-f".into());
        args.push("rawvideo".into());
        args.push("-pix_fmt".into());
        args.push("rgb24".into());
        args.push("pipe:1".into());

        let mut child = Command::new("ffmpeg")
            .args(&args)
            .stdout(Stdio::piped())
            .stderr(Stdio::null())
            .stdin(Stdio::null())
            .spawn()?;
        let stdout = child
            .stdout
            .take()
            .ok_or_else(|| io::Error::other("ffmpeg produced no stdout pipe"))?;

        Ok(Decoder {
            child,
            stdout,
            out_w,
            out_h,
            frame_bytes,
            out_fps,
            index: 0,
            max_frames: opts.max_frames,
            done: false,
        })
    }

    /// Output frame dimensions (after any scale).
    pub fn dimensions(&self) -> (u32, u32) {
        (self.out_w, self.out_h)
    }

    fn read_one(&mut self) -> io::Result<Option<Frame>> {
        if self.done {
            return Ok(None);
        }
        if let Some(n) = self.max_frames {
            if self.index >= n {
                self.done = true;
                return Ok(None);
            }
        }
        let mut buf = vec![0u8; self.frame_bytes];
        match read_full(&mut self.stdout, &mut buf) {
            // Full frame.
            Ok(n) if n == self.frame_bytes => {
                let pts_s = if self.out_fps > 0.0 {
                    self.index as f64 / self.out_fps
                } else {
                    0.0
                };
                let frame = Frame {
                    index: self.index,
                    pts_s,
                    width: self.out_w,
                    height: self.out_h,
                    rgb: buf,
                };
                self.index += 1;
                Ok(Some(frame))
            }
            // Clean EOF on a frame boundary.
            Ok(0) => {
                self.done = true;
                Ok(None)
            }
            // Truncated tail = corrupt/partial last frame; treat as EOF but surface it.
            Ok(n) => {
                self.done = true;
                Err(io::Error::other(format!(
                    "ffmpeg returned a partial frame: got {n} of {} bytes",
                    self.frame_bytes
                )))
            }
            Err(e) => {
                self.done = true;
                Err(e)
            }
        }
    }

    /// Reap the child and return ffmpeg's exit status. Call after the iterator is drained.
    pub fn finish(mut self) -> io::Result<std::process::ExitStatus> {
        self.child.wait()
    }
}

impl Iterator for Decoder {
    type Item = io::Result<Frame>;
    fn next(&mut self) -> Option<Self::Item> {
        self.read_one().transpose()
    }
}

impl Drop for Decoder {
    fn drop(&mut self) {
        // Don't leak the subprocess if the iterator is abandoned early.
        let _ = self.child.kill();
        let _ = self.child.wait();
    }
}

/// Read until `buf` is full or EOF. Returns the number of bytes read (== buf.len() unless EOF).
/// A pipe read can return short, so loop until satisfied — otherwise frames tear.
fn read_full(r: &mut impl Read, buf: &mut [u8]) -> io::Result<usize> {
    let mut filled = 0;
    while filled < buf.len() {
        match r.read(&mut buf[filled..]) {
            Ok(0) => break,
            Ok(n) => filled += n,
            Err(ref e) if e.kind() == io::ErrorKind::Interrupted => continue,
            Err(e) => return Err(e),
        }
    }
    Ok(filled)
}

/// A streaming RGB24 frame source backed by an arbitrary `Read` (e.g. process stdin) instead of
/// an ffmpeg subprocess. The bytes on the reader are already packed RGB24 at a fixed
/// `width`x`height` — exactly the layout [`Decoder`] hands downstream — so this is the *same*
/// `Frame` stream with the mp4 encode/decode hop removed. It is the in-memory transport for a
/// real-time closed loop: a renderer writes raw RGB24 to the pipe, third-eye perceives it directly.
///
/// Timestamps are reconstructed from `fps` (`pts_s = index / fps`), identical to [`Decoder`]'s
/// constant-rate reconstruction — there is no per-frame PTS on a raw pipe either. Frames are read
/// one at a time, so memory stays O(one frame).
///
/// Implements `Iterator<Item = io::Result<Frame>>`, so it drops in anywhere [`Decoder`] is iterated.
pub struct RawFrameSource<R: Read> {
    reader: R,
    width: u32,
    height: u32,
    frame_bytes: usize,
    fps: f64,
    index: u64,
    max_frames: Option<u64>,
    done: bool,
}

impl<R: Read> RawFrameSource<R> {
    /// Build a raw RGB24 source over `reader`. `width`x`height` are the packed frame dimensions
    /// (stride == width*3); `fps` reconstructs the presentation clock; `max_frames` caps the
    /// stream (`None` = until EOF). Dimensions must be non-zero.
    pub fn new(
        reader: R,
        width: u32,
        height: u32,
        fps: f64,
        max_frames: Option<u64>,
    ) -> io::Result<Self> {
        if width == 0 || height == 0 {
            return Err(io::Error::other(
                "RawFrameSource requires non-zero width and height",
            ));
        }
        let frame_bytes = (width as usize) * (height as usize) * 3;
        Ok(RawFrameSource {
            reader,
            width,
            height,
            frame_bytes,
            fps,
            index: 0,
            max_frames,
            done: false,
        })
    }

    /// Output frame dimensions.
    pub fn dimensions(&self) -> (u32, u32) {
        (self.width, self.height)
    }

    fn read_one(&mut self) -> io::Result<Option<Frame>> {
        if self.done {
            return Ok(None);
        }
        if let Some(n) = self.max_frames {
            if self.index >= n {
                self.done = true;
                return Ok(None);
            }
        }
        let mut buf = vec![0u8; self.frame_bytes];
        match read_full(&mut self.reader, &mut buf) {
            // Full frame.
            Ok(n) if n == self.frame_bytes => {
                let pts_s = if self.fps > 0.0 {
                    self.index as f64 / self.fps
                } else {
                    0.0
                };
                let frame = Frame {
                    index: self.index,
                    pts_s,
                    width: self.width,
                    height: self.height,
                    rgb: buf,
                };
                self.index += 1;
                Ok(Some(frame))
            }
            // Clean EOF on a frame boundary.
            Ok(0) => {
                self.done = true;
                Ok(None)
            }
            // Truncated tail = partial last frame; treat as EOF but surface it (parity with Decoder).
            Ok(n) => {
                self.done = true;
                Err(io::Error::other(format!(
                    "raw frame source returned a partial frame: got {n} of {} bytes",
                    self.frame_bytes
                )))
            }
            Err(e) => {
                self.done = true;
                Err(e)
            }
        }
    }
}

impl<R: Read> Iterator for RawFrameSource<R> {
    type Item = io::Result<Frame>;
    fn next(&mut self) -> Option<Self::Item> {
        self.read_one().transpose()
    }
}

/// Convenience: probe + decode in one call, collecting all frames (bounded by `opts.max_frames`).
/// For streaming use the [`Decoder`] iterator directly.
pub fn decode_all(path: &str, opts: &DecodeOptions) -> io::Result<(VideoInfo, Vec<Frame>)> {
    let info = probe(path)?;
    let dec = Decoder::open(path, &info, opts)?;
    let mut frames = Vec::new();
    for f in dec {
        frames.push(f?);
    }
    Ok((info, frames))
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Two synthetic RGB24 frames over an in-memory reader yield the exact `Frame` shape the
    /// ffmpeg `Decoder` produces: right dims, right byte length, and PTS reconstructed from fps.
    #[test]
    fn raw_source_yields_decoder_shaped_frames() {
        let (w, h, fps) = (4u32, 3u32, 24.0f64);
        let fb = (w * h * 3) as usize;
        // frame 0 all 0x11, frame 1 all 0x22 — distinct content per frame.
        let mut bytes = vec![0x11u8; fb];
        bytes.extend(std::iter::repeat(0x22u8).take(fb));
        let src = RawFrameSource::new(&bytes[..], w, h, fps, None).unwrap();
        let frames: Vec<Frame> = src.map(|f| f.unwrap()).collect();
        assert_eq!(frames.len(), 2);
        for (i, f) in frames.iter().enumerate() {
            assert_eq!(f.index, i as u64);
            assert_eq!(f.width, w);
            assert_eq!(f.height, h);
            assert_eq!(f.rgb.len(), fb, "stride == width*3, packed RGB24");
            // PTS reconstructed from the supplied fps, identical to Decoder::read_one.
            assert!((f.pts_s - i as f64 / fps).abs() < 1e-12);
        }
        assert_eq!(frames[0].rgb[0], 0x11);
        assert_eq!(frames[1].rgb[0], 0x22);
    }

    /// `max_frames` caps the stream even when more bytes are available (the cadence cap path).
    #[test]
    fn raw_source_respects_max_frames() {
        let (w, h) = (2u32, 2u32);
        let fb = (w * h * 3) as usize;
        let bytes = vec![0u8; fb * 5];
        let src = RawFrameSource::new(&bytes[..], w, h, 30.0, Some(2)).unwrap();
        assert_eq!(src.count(), 2);
    }

    /// A truncated final frame surfaces an error (parity with Decoder's partial-frame handling),
    /// not a silently torn frame.
    #[test]
    fn raw_source_partial_frame_is_error() {
        let (w, h) = (2u32, 2u32);
        let fb = (w * h * 3) as usize;
        // one full frame + a half frame
        let bytes = vec![0u8; fb + fb / 2];
        let mut src = RawFrameSource::new(&bytes[..], w, h, 30.0, None).unwrap();
        assert!(src.next().unwrap().is_ok()); // first full frame
        assert!(src.next().unwrap().is_err()); // truncated tail -> error
        assert!(src.next().is_none()); // done after the error
    }

    #[test]
    fn raw_source_rejects_zero_dims() {
        assert!(RawFrameSource::new(&[][..], 0, 10, 24.0, None).is_err());
        assert!(RawFrameSource::new(&[][..], 10, 0, 24.0, None).is_err());
    }
}
